export function getLeafImage(keywords?: string): string | null {
  if (!keywords) return null;
  // Split on commas, spaces and slashes so 'Mens Wear', 'mens-wear', 'suit,men' all work.
  const tokens = keywords.toLowerCase().split(/[\s,\/]+/).map(k => k.trim()).filter(Boolean);
  // 1. Try whole string (after lowercase + dash normalisation) as one key.
  const whole = keywords.toLowerCase().trim().replace(/\s+/g, '-');
  if (LEAF_IMAGE_MAP[whole]) return LEAF_IMAGE_MAP[whole];
  // 2. EXACT token matches only.
  for (const key of tokens) if (LEAF_IMAGE_MAP[key]) return LEAF_IMAGE_MAP[key];
  return null;
}
